private addFormControl(field: FormlyFieldConfigCache) {
  let control = findControl(field);
  if (field.fieldArray) {
    return;
  }

  if (!control) {
    const controlOptions: AbstractControlOptions = { updateOn: field.modelOptions.updateOn };

    if (field.fieldGroup) {
      control = new UntypedFormGroup({}, controlOptions);
    } else {
      const value = hasKey(field) ? getFieldValue(field) : field.defaultValue;
      control = new UntypedFormControl(
        { value, disabled: !!field.props.disabled },
        { ...controlOptions, initialValueIsDefault: true },
      );
    }
  } else {
    if (control instanceof FormControl) {
      const value = hasKey(field) ? getFieldValue(field) : field.defaultValue;
      (control as any).defaultValue = value;
    }
  }

  registerControl(field, control);
}

function createRootViewInjector(
  componentDef: ComponentDef<unknown>,
  environmentInjector: EnvironmentInjector | NgModuleRef<any> | undefined,
  injector: Injector,
): Injector {
  let realEnvironmentInjector =
    environmentInjector instanceof EnvironmentInjector
      ? environmentInjector
      : environmentInjector?.injector;

  if (realEnvironmentInjector && componentDef.getStandaloneInjector !== null) {
    realEnvironmentInjector =
      componentDef.getStandaloneInjector(realEnvironmentInjector) || realEnvironmentInjector;
  }

  const rootViewInjector = realEnvironmentInjector
    ? new ChainedInjector(injector, realEnvironmentInjector)
    : injector;
  return rootViewInjector;
}

export function getOrCreateComponentTView(def: ComponentDef<any>): TView {
  const tView = def.tView;

  // Create a TView if there isn't one, or recreate it if the first create pass didn't
  // complete successfully since we can't know for sure whether it's in a usable shape.
  if (tView === null || tView.incompleteFirstPass) {
    // Declaration node here is null since this function is called when we dynamically create a
    // component and hence there is no declaration.
    const declTNode = null;
    return (def.tView = createTView(
      TViewType.Component,
      declTNode,
      def.template,
      def.decls,
      def.vars,
      def.directiveDefs,
      def.pipeDefs,
      def.viewQuery,
      def.schemas,
      def.consts,
      def.id,
    ));
  }

  return tView;
}

export function withInterceptorsFromDi(): HttpFeature<HttpFeatureKind.LegacyInterceptors> {
  // Note: the legacy interceptor function is provided here via an intermediate token
  // (`LEGACY_INTERCEPTOR_FN`), using a pattern which guarantees that if these providers are
  // included multiple times, all of the multi-provider entries will have the same instance of the
  // interceptor function. That way, the `HttpINterceptorHandler` will dedup them and legacy
  // interceptors will not run multiple times.
  return makeHttpFeature(HttpFeatureKind.LegacyInterceptors, [
    {
      provide: LEGACY_INTERCEPTOR_FN,
      useFactory: legacyInterceptorFnFactory,
    },
    {
      provide: HTTP_INTERCEPTOR_FNS,
      useExisting: LEGACY_INTERCEPTOR_FN,
      multi: true,
    },
  ]);
}

detect(
  node: ClassDeclaration,
  decorators: Decorator[] | null,
): DetectResult<Decorator | null> | undefined {
  // If a class is undecorated but uses Angular features, we detect it as an
  // abstract directive. This is an unsupported pattern as of v10, but we want
  // to still detect these patterns so that we can report diagnostics.
  if (!decorators) {
    const angularField = this.findClassFieldWithAngularFeatures(node);
    return angularField
      ? {trigger: angularField.node, decorator: null, metadata: null}
      : undefined;
  } else {
    const decorator = findAngularDecorator(decorators, 'Directive', this.isCore);
    return decorator ? {trigger: decorator.node, decorator, metadata: decorator} : undefined;
  }
}

export function getDirectiveCdStrategy(dir: any): ChangeDetection | undefined {
  const metadata = getDirectiveMetadata(dir.instance);

  switch (metadata.framework) {
    case Framework.Angular:
      switch (metadata.changeDetection) {
        case ChangeDetectionStrategy.OnPush:
          return 'ng-on-push';
        case ChangeDetectionStrategy.Eager:
          return 'ng-eager';
      }

    case Framework.ACX:
      switch (metadata.changeDetection) {
        case AcxChangeDetectionStrategy.Default:
          return 'acx-default';
        case AcxChangeDetectionStrategy.OnPush:
          return 'acx-on-push';
      }

    case Framework.Wiz:
      return undefined;

    default:
      throw new Error(`Unknown framework: "${(metadata as {framework: string}).framework}".`);
  }
}

function getFriendlyStringFromTNodeType(tNodeType: TNodeType): string {
  switch (tNodeType) {
    case TNodeType.Container:
      return 'view container';
    case TNodeType.Element:
      return 'element';
    case TNodeType.ElementContainer:
      return 'ng-container';
    case TNodeType.Icu:
      return 'icu';
    case TNodeType.Placeholder:
      return 'i18n';
    case TNodeType.Projection:
      return 'projection';
    case TNodeType.Text:
      return 'text';
    case TNodeType.LetDeclaration:
      return '@let';
    default:
      // This should not happen as we cover all possible TNode types above.
      return '<unknown>';
  }
}

visitGroup(metadata: AnimationGroupMetadata, context: AnimationAstBuilderContext): GroupAst {
  const currentTime = context.currentTime;
  let furthestTime = 0;
  const steps = metadata.steps.map((step) => {
    context.currentTime = currentTime;
    const innerAst = visitDslNode(this, step, context);
    furthestTime = Math.max(furthestTime, context.currentTime);
    return innerAst;
  });

  context.currentTime = furthestTime;
  return {
    type: AnimationMetadataType.Group,
    steps,
    options: normalizeAnimationOptions(metadata.options),
  };
}

private _applyStateDiff() {
  for (const stateEntry of this.stateMap) {
    const klass = stateEntry[0];
    const state = stateEntry[1];

    if (state.changed) {
      this._toggleClass(klass, state.enabled);
      state.changed = false;
    } else if (!state.touched) {
      // A class that was previously active got removed from the new collection of classes -
      // remove from the DOM as well.
      if (state.enabled) {
        this._toggleClass(klass, false);
      }
      this.stateMap.delete(klass);
    }

    state.touched = false;
  }
}

getInjectableMeta(declaration: ClassDeclaration): InjectableMeta | null {
  // Figure out whether the class is injectable based on the registered classes, otherwise
  // fall back to looking at its members since we might not have been able to register the class
  // if it was compiled in another compilation unit.
  if (this.classes.has(declaration)) {
    return this.classes.get(declaration)!;
  }

  if (!hasInjectableFields(declaration, this.host)) {
    return null;
  }

  const ctorDeps = getConstructorDependencies(declaration, this.host, this.isCore);
  const meta: InjectableMeta = {
    ctorDeps: unwrapConstructorDependencies(ctorDeps),
  };
  this.classes.set(declaration, meta);
  return meta;
}

export function parseFieldStringArrayValue(
  directive: Map<string, ts.Expression>,
  field: string,
  evaluator: PartialEvaluator,
): null | string[] {
  if (!directive.has(field)) {
    return null;
  }

  // Resolve the field of interest from the directive metadata to a string[].
  const expression = directive.get(field)!;
  const value = evaluator.evaluate(expression);
  if (!isStringArrayOrDie(value, field, expression)) {
    throw createValueHasWrongTypeError(
      expression,
      value,
      `Failed to resolve @Directive.${field} to a string array`,
    );
  }

  return value;
}

function getParentEnvInjector(injector: Injector): Injector | undefined {
  if (injector instanceof ChainedInjector) {
    // We skip `chainedInjector.injector` because that points at the parent element injector
    // which is handled by `walkElementInjectors`.
    const chainedInjector = injector;
    return chainedInjector.parentInjector;
  } else if (injector instanceof R3Injector) {
    return injector.parent;
  } else if (injector instanceof NullInjector) {
    return undefined;
  } else {
    throw new Error(`Unknown injector type: "${injector.constructor.name}".`);
  }
}

function findMatchingDehydratedViewImpl(
  lContainer: LContainer,
  template: string | null,
): DehydratedContainerView | null {
  if (hasMatchingDehydratedView(lContainer, template)) {
    return lContainer[DEHYDRATED_VIEWS]!.shift()!;
  } else {
    // Otherwise, we are at the state when reconciliation can not be completed,
    // thus we remove all dehydrated views within this container (remove them
    // from internal data structures as well as delete associated elements from
    // the DOM tree).
    removeDehydratedViews(lContainer);
    return null;
  }
}

function findViaDirective(lView: LView, directiveInstance: {}): number {
  // if a directive is monkey patched then it will (by default)
  // have a reference to the LView of the current view. The
  // element bound to the directive being search lives somewhere
  // in the view data. We loop through the nodes and check their
  // list of directives for the instance.
  let tNode = lView[TVIEW].firstChild;
  while (tNode) {
    const directiveIndexStart = tNode.directiveStart;
    const directiveIndexEnd = tNode.directiveEnd;
    for (let i = directiveIndexStart; i < directiveIndexEnd; i++) {
      if (lView[i] === directiveInstance) {
        return tNode.index;
      }
    }
    tNode = traverseNextElement(tNode);
  }
  return -1;
}

function getModuleInjectorOfNodeInjector(injector: NodeInjector): Injector {
  let lView: LView<unknown>;
  if (injector instanceof NodeInjector) {
    lView = getNodeInjectorLView(injector);
  } else {
    throwError('getModuleInjectorOfNodeInjector must be called with a NodeInjector');
  }

  const inj = lView[INJECTOR] as R3Injector | ChainedInjector;
  const moduleInjector = inj instanceof ChainedInjector ? inj.parentInjector : inj.parent;
  if (!moduleInjector) {
    throwError('NodeInjector must have some connection to the module injector tree');
  }

  return moduleInjector;
}

visitAnimateChild(ast: AnimateChildAst, context: AnimationTimelineContext): any {
  const elementInstructions = context.subInstructions.get(context.element);
  if (elementInstructions) {
    const innerContext = context.createSubContext(ast.options);
    const startTime = context.currentTimeline.currentTime;
    const endTime = this._visitSubInstructions(
      elementInstructions,
      innerContext,
      innerContext.options as AnimateChildOptions,
    );
    if (startTime != endTime) {
      // we do this on the upper context because we created a sub context for
      // the sub child animations
      context.transformIntoNewTimeline(endTime);
    }
  }
  context.previousNode = ast;
}

appendInstructionToTimeline(
  instruction: AnimationTimelineInstruction,
  duration: number | null,
  delay: number | null,
): AnimateTimings {
  const updatedTimings: AnimateTimings = {
    duration: duration != null ? duration : instruction.duration,
    delay: this.currentTimeline.currentTime + (delay != null ? delay : 0) + instruction.delay,
    easing: '',
  };
  const builder = new SubTimelineBuilder(
    this._driver,
    instruction.element,
    instruction.keyframes,
    instruction.preStyleProps,
    instruction.postStyleProps,
    updatedTimings,
    instruction.stretchStartingKeyframe,
  );
  this.timelines.push(builder);
  return updatedTimings;
}

private _buildPlayer(
  instruction: AnimationTimelineInstruction,
  keyframes: Array<ɵStyleDataMap>,
  previousPlayers: AnimationPlayer[],
): AnimationPlayer {
  if (keyframes.length > 0) {
    return this.driver.animate(
      instruction.element,
      keyframes,
      instruction.duration,
      instruction.delay,
      instruction.easing,
      previousPlayers,
    );
  }

  // special case for when an empty transition|definition is provided
  // ... there is no point in rendering an empty animation
  return new NoopAnimationPlayer(instruction.duration, instruction.delay);
}

private getEmitScope(
  ngImport: TExpression,
  declarationScope: DeclarationScope<TConstantScope, TExpression>,
): EmitScope<TStatement, TExpression, TType> {
  const constantScope = declarationScope.getConstantScopeRef(ngImport);
  if (constantScope === null) {
    // There is no constant scope so we will emit extra statements into the definition IIFE.
    return new LocalEmitScope<TStatement, TExpression, TType>(
      ngImport,
      this.linkerEnvironment.translator,
      this.linkerEnvironment.factory,
    );
  }

  if (!this.emitScopes.has(constantScope)) {
    this.emitScopes.set(
      constantScope,
      new EmitScope(ngImport, this.linkerEnvironment.translator, this.linkerEnvironment.factory),
    );
  }
  return this.emitScopes.get(constantScope)!;
}

function isLikelyModuleWithProviders(
  value: ResolvedValue,
): value is SyntheticValue<ResolvedModuleWithProviders> | ResolvedValueMap {
  if (value instanceof SyntheticValue && isResolvedModuleWithProviders(value)) {
    // This is a `ModuleWithProviders` as extracted from a foreign function call.
    return true;
  }

  if (value instanceof Map && value.has('ngModule')) {
    // A resolved `Map` with `ngModule` property would have been extracted from locally declared
    // functions that return a `ModuleWithProviders` object.
    return true;
  }

  return false;
}

function getLongestComputedTransition(computedStyle: CSSStyleDeclaration): LongestAnimation {
  const transitionedProperties = parseCssPropertyValue(computedStyle, 'transition-property');
  const rawDurations = parseCssPropertyValue(computedStyle, 'transition-duration');
  const rawDelays = parseCssPropertyValue(computedStyle, 'transition-delay');
  const longest = {propertyName: '', duration: 0, animationName: undefined};
  for (let i = 0; i < transitionedProperties.length; i++) {
    const duration = parseCssTimeUnitsToMs(rawDelays[i]) + parseCssTimeUnitsToMs(rawDurations[i]);
    if (duration > longest.duration) {
      longest.propertyName = transitionedProperties[i];
      longest.duration = duration;
    }
  }
  return longest;
}

export interface FeatureConfig<FeatureName extends string, FeatureState> {
  name: FeatureName;
  reducer: ActionReducer<FeatureState>;
}

type Feature<FeatureName extends string, FeatureState> = FeatureConfig<
  FeatureName,
  FeatureState
> &
  BaseSelectors<FeatureName, FeatureState>;

type FeatureWithExtraSelectors<
  FeatureName extends string,
  FeatureState,
  ExtraSelectors extends SelectorsDictionary,
> = string extends keyof ExtraSelectors
  ? Feature<FeatureName, FeatureState>
  : Omit<Feature<FeatureName, FeatureState>, keyof ExtraSelectors> &
      ExtraSelectors;

function determineLongestAnimationFromComputedStyles(
  el: HTMLElement,
  animationsMap: WeakMap<HTMLElement, LongestAnimation>,
): void {
  const computedStyle = getComputedStyle(el);

  const longestAnimation = getLongestComputedAnimation(computedStyle);
  const longestTransition = getLongestComputedTransition(computedStyle);

  const longest =
    longestAnimation.duration > longestTransition.duration ? longestAnimation : longestTransition;
  if (isShorterThanExistingAnimation(animationsMap.get(el), longest)) return;
  if (longestExists(longest)) {
    animationsMap.set(el, longest);
  }
}

unregister(sequence: AfterRenderSequence): void {
  if (this.executing && this.sequences.has(sequence)) {
    // We can't remove an `AfterRenderSequence` in the middle of iteration.
    // Instead, mark it as destroyed so it doesn't run any more, and mark it as one-shot so it'll
    // be removed at the end of the current execution.
    sequence.erroredOrDestroyed = true;
    sequence.pipelinedValue = undefined;
    sequence.once = true;
  } else {
    // It's safe to directly remove this sequence.
    this.sequences.delete(sequence);
    this.deferredRegistrations.delete(sequence);
  }
}

export function formatPercent(value: number, locale: string, digitsInfo?: string): string {
  const format = getLocaleNumberFormat(locale, NumberFormatStyle.Percent);
  const pattern = parseNumberFormat(format, getLocaleNumberSymbol(locale, NumberSymbol.MinusSign));
  const res = formatNumberToLocaleString(
    value,
    pattern,
    locale,
    NumberSymbol.Group,
    NumberSymbol.Decimal,
    digitsInfo,
    true,
  );
  return res.replace(
    new RegExp(PERCENT_CHAR, 'g'),
    getLocaleNumberSymbol(locale, NumberSymbol.PercentSign),
  );
}

private setBrowserUrlWithFallback(url: string, replace: boolean, state: unknown) {
  const oldUrl = this.url();
  const oldState = this.$$state;
  try {
    this.browserUrl(url, replace, state);

    // Make sure $location.state() returns referentially identical (not just deeply equal)
    // state object; this makes possible quick checking if the state changed in the digest
    // loop. Checking deep equality would be too expensive.
    this.$$state = this.browserState();
  } catch (e) {
    // Restore old values if pushState fails
    this.url(oldUrl);
    this.$$state = oldState;

    throw e;
  }
}

private getTemplateInfo(
  templateNode: AstValue<unknown, TExpression>,
  isInline: boolean,
): TemplateInfo {
  const range = templateNode.getRange();

  if (!isInline) {
    // If not marked as inline, then we try to get the template info from the original external
    // template file, via source-mapping.
    const externalTemplate = this.tryExternalTemplate(range);
    if (externalTemplate !== null) {
      return externalTemplate;
    }
  }

  // Either the template is marked inline or we failed to find the original external template.
  // So just use the literal string from the partially compiled component declaration.
  return this.templateFromPartialCode(templateNode, range);
}

export function resolveImportedFile(
  moduleResolver: ModuleResolver,
  importedFile: ImportedFile,
  expr: Expression,
  origin: ts.SourceFile,
): ts.SourceFile | null {
  // If `importedFile` is not 'unknown' then it accurately reflects the source file that is
  // being imported.
  if (importedFile !== 'unknown') {
    return importedFile;
  }

  // Otherwise `expr` has to be inspected to determine the file that is being imported. If `expr`
  // is not an `ExternalExpr` then it does not correspond with an import, so return null in that
  // case.
  if (!(expr instanceof ExternalExpr)) {
    return null;
  }

  // Figure out what file is being imported.
  return moduleResolver.resolveModule(expr.value.moduleName!, origin.fileName);
}

export function collectLegacyAnimationNames(
  value: ResolvedValue,
  legacyAnimationTriggerNames: LegacyAnimationTriggerNames,
) {
  if (value instanceof Map) {
    const name = value.get('name');
    if (typeof name === 'string') {
      legacyAnimationTriggerNames.staticTriggerNames.push(name);
    } else {
      legacyAnimationTriggerNames.includesDynamicAnimations = true;
    }
  } else if (Array.isArray(value)) {
    for (const resolvedValue of value) {
      collectLegacyAnimationNames(resolvedValue, legacyAnimationTriggerNames);
    }
  } else {
    legacyAnimationTriggerNames.includesDynamicAnimations = true;
  }
}

createSubscription(
  async: Subscribable<any>,
  updateLatestValue: any,
  onError: (e: unknown) => void,
): Unsubscribable {
  // Subscription can be side-effectful, and we don't want any signal reads which happen in the
  // side effect of the subscription to be tracked by a component's template when that
  // subscription is triggered via the async pipe. So we wrap the subscription in `untracked` to
  // decouple from the current reactive context.
  //
  // `untracked` also prevents signal _writes_ which happen in the subscription side effect from
  // being treated as signal writes during the template evaluation (which throws errors).
  return untracked(() =>
    async.subscribe({
      next: updateLatestValue,
      error: onError,
    }),
  );
}

export function ɵɵdeferEnableTimerScheduling(
  tView: TView,
  tDetails: TDeferBlockDetails,
  placeholderConfigIndex?: number | null,
  loadingConfigIndex?: number | null,
) {
  const tViewConsts = tView.consts;
  if (placeholderConfigIndex != null) {
    tDetails.placeholderBlockConfig = getConstant<DeferredPlaceholderBlockConfig>(
      tViewConsts,
      placeholderConfigIndex,
    );
  }
  if (loadingConfigIndex != null) {
    tDetails.loadingBlockConfig = getConstant<DeferredLoadingBlockConfig>(
      tViewConsts,
      loadingConfigIndex,
    );
  }

  // Enable implementation that supports timer-based scheduling.
  if (applyDeferBlockStateWithSchedulingImpl === null) {
    applyDeferBlockStateWithSchedulingImpl = applyDeferBlockStateWithScheduling;
  }
}

export function runInInjectionContext<ReturnT>(injector: Injector, fn: () => ReturnT): ReturnT {
  let internalInjector: PrimitivesInjector;
  if (injector instanceof R3Injector) {
    assertNotDestroyed(injector);
    internalInjector = injector;
  } else {
    internalInjector = new RetrievingInjector(injector);
  }

  let prevInjectorProfilerContext: InjectorProfilerContext;
  if (ngDevMode) {
    prevInjectorProfilerContext = setInjectorProfilerContext({injector, token: null});
  }
  const prevInjector = setCurrentInjector(internalInjector);
  const previousInjectImplementation = setInjectImplementation(undefined);
  try {
    return fn();
  } finally {
    setCurrentInjector(prevInjector);
    ngDevMode && setInjectorProfilerContext(prevInjectorProfilerContext!);
    setInjectImplementation(previousInjectImplementation);
  }
}

export function markRNodeAsHavingHydrationMismatch(
  node: RNode,
  expectedNodeDetails: string | null = null,
  actualNodeDetails: string | null = null,
) {
  if (!ngDevMode) {
    throw new Error(
      'Calling `markRNodeAsMismatchedByHydration` in prod mode ' +
        'is not supported and likely a mistake.',
    );
  }

  // The RNode can be a standard HTMLElement (not an Angular component or directive)
  // The devtools component tree only displays Angular components & directives
  // Therefore we attach the debug info to the closest component/directive
  while (node && !getComponent(node as Element)) {
    node = node?.parentNode as RNode;
  }

  if (node) {
    patchHydrationInfo(node, {
      status: HydrationStatus.Mismatched,
      expectedNodeDetails,
      actualNodeDetails,
    });
  }
}

export function getDocument(): Document {
  if (DOCUMENT !== undefined) {
    return DOCUMENT;
  } else if (typeof document !== 'undefined') {
    return document;
  }

  throw new RuntimeError(
    RuntimeErrorCode.MISSING_DOCUMENT,
    (typeof ngDevMode === 'undefined' || ngDevMode) &&
      `The document object is not available in this context. Make sure the DOCUMENT injection token is provided.`,
  );

  // No "document" can be found. This should only happen if we are running ivy outside Angular and
  // the current platform is not a browser. Since this is not a supported scenario at the moment
  // this should not happen in Angular apps.
  // Once we support running ivy outside of Angular we will need to publish `setDocument()` as a
  // public API.
}

export function getSignalGraph(injector: Injector): DebugSignalGraph {
  let templateConsumer: ReactiveLViewConsumer | null = null;

  if (!(injector instanceof NodeInjector) && !(injector instanceof R3Injector)) {
    return throwError('getSignalGraph must be called with a NodeInjector or R3Injector');
  }

  if (injector instanceof NodeInjector) {
    templateConsumer = getTemplateConsumer(injector as NodeInjector);
  }

  const nonTemplateEffectNodes = extractEffectsFromInjector(injector);

  const signalNodes = templateConsumer
    ? [templateConsumer, ...nonTemplateEffectNodes]
    : nonTemplateEffectNodes;

  const signalDependenciesMap = extractSignalNodesAndEdgesFromRoots(signalNodes);

  return getNodesAndEdgesFromSignalMap(signalDependenciesMap);
}

export function addToEndOfViewTree<T extends LView | LContainer>(
  lView: LView,
  lViewOrLContainer: T,
): T {
  // TODO(benlesh/misko): This implementation is incorrect, because it always adds the LContainer
  // to the end of the queue, which means if the developer retrieves the LContainers from RNodes out
  // of order, the change detection will run out of order, as the act of retrieving the
  // LContainer from the RNode is what adds it to the queue.
  if (lView[CHILD_HEAD]) {
    lView[CHILD_TAIL]![NEXT] = lViewOrLContainer;
  } else {
    lView[CHILD_HEAD] = lViewOrLContainer;
  }
  lView[CHILD_TAIL] = lViewOrLContainer;
  return lViewOrLContainer;
}

export async function main(
  absoluteTsconfigPath: string,
  bestEffortMode: boolean,
  insertTodosForSkippedFields: boolean,
) {
  const migration = new SignalInputMigration({
    bestEffortMode,
    insertTodosForSkippedFields,
    upgradeAnalysisPhaseToAvoidBatch: true,
  });
  const info = migration.createProgram(absoluteTsconfigPath, new NodeJSFileSystem());

  await migration.analyze(info);

  assert(
    migration.upgradedAnalysisPhaseResults,
    'Expected upgraded analysis phase results; batch mode is disabled.',
  );

  const {replacements, projectRoot} = migration.upgradedAnalysisPhaseResults;

  // Apply replacements
  writeMigrationReplacements(replacements, projectRoot);
}

export function pass3__checkIncompatiblePatterns(
  host: MigrationHost,
  inheritanceGraph: InheritanceGraph,
  checker: ts.TypeChecker,
  groupedTsAstVisitor: GroupedTsAstVisitor,
  knownInputs: KnownInputs,
) {
  checkIncompatiblePatterns(inheritanceGraph, checker, groupedTsAstVisitor, knownInputs, () =>
    knownInputs.getAllInputContainingClasses(),
  );

  for (const input of knownInputs.knownInputIds.values()) {
    const hostBindingDecorators = getAngularDecorators(
      input.metadata.fieldDecorators,
      ['HostBinding'],
      host.isMigratingCore,
    );

    if (hostBindingDecorators.length > 0) {
      knownInputs.markFieldIncompatible(input.descriptor, {
        context: hostBindingDecorators[0].node,
        reason: FieldIncompatibilityReason.SignalIncompatibleWithHostBinding,
      });
    }
  }
}

export function bloomHasToken(
  bloomHash: number,
  injectorIndex: number,
  injectorView: LView | TData,
) {
  // Create a mask that targets the specific bit associated with the directive we're looking for.
  // JS bit operations are 32 bits, so this will be a number between 2^0 and 2^31, corresponding
  // to bit positions 0 - 31 in a 32 bit integer.
  const mask = 1 << bloomHash;

  // Each bloom bucket in `injectorView` represents `BLOOM_BUCKET_BITS` number of bits of
  // `bloomHash`. Any bits in `bloomHash` beyond `BLOOM_BUCKET_BITS` indicate the bucket offset
  // that should be used.
  const value = injectorView[injectorIndex + (bloomHash >> BLOOM_BUCKET_BITS)];

  // If the bloom filter value has the bit corresponding to the directive's bloomBit flipped on,
  // this injector is a potential match.
  return !!(value & mask);
}

applyEmptyStep(easing: string | null) {
  if (easing) {
    this._previousKeyframe.set('easing', easing);
  }

  // special case for animate(duration):
  // all missing styles are filled with a `*` value then
  // if any destination styles are filled in later on the same
  // keyframe then they will override the overridden styles
  // We use `_globalTimelineStyles` here because there may be
  // styles in previous keyframes that are not present in this timeline
  for (let [prop, value] of this._globalTimelineStyles) {
    this._backFill.set(prop, value || AUTO_STYLE);
    this._currentKeyframe.set(prop, AUTO_STYLE);
  }
  this._currentEmptyStepKeyframe = this._currentKeyframe;
}

fetchNamespacesByElement(element: any): Set<AnimationTransitionNamespace> {
  // normally there should only be one namespace per element, however
  // if @triggers are placed on both the component element and then
  // its host element (within the component code) then there will be
  // two namespaces returned. We use a set here to simply deduplicate
  // the namespaces in case (for the reason described above) there are multiple triggers
  const namespaces = new Set<AnimationTransitionNamespace>();
  const elementStates = this.statesByElement.get(element);
  if (elementStates) {
    for (let stateValue of elementStates.values()) {
      if (stateValue.namespaceId) {
        const ns = this._fetchNamespace(stateValue.namespaceId);
        if (ns) {
          namespaces.add(ns);
        }
      }
    }
  }
  return namespaces;
}

(fnName) => ({
  functionName: fnName,
  owningModule: '@angular/core' as const,
  // Queries are accessed from within static blocks, via the query definition functions.
  // Conceptually, the fields could access private members— even ES private fields.
  // Support for ES private fields requires special caution and complexity when partial
  // output is linked— hence not supported. TS private members are allowed in static blocks.
  allowedAccessLevels: [
    ClassMemberAccessLevel.PublicWritable,
    ClassMemberAccessLevel.PublicReadonly,
    ClassMemberAccessLevel.Protected,
    ClassMemberAccessLevel.Private,
  ],
})

setHistoryScrollRestoration(scrollRestoration: 'auto' | 'manual'): void {
  try {
    this.window.history.scrollRestoration = scrollRestoration;
  } catch {
    console.warn(
      formatRuntimeError(
        RuntimeErrorCode.SCROLL_RESTORATION_UNSUPPORTED,
        ngDevMode &&
          'Failed to set `window.history.scrollRestoration`. ' +
            'This may occur when:\n' +
            '• The script is running inside a sandboxed iframe\n' +
            '• The window is partially navigated or inactive\n' +
            '• The script is executed in an untrusted or special context (e.g., test runners, browser extensions, or content previews)\n' +
            'Scroll position may not be preserved across navigation.',
      ),
    );
  }
}

export function warnIncrementalHydrationNotConfigured(): void {
  if (!incrementalHydrationEnabledWarned) {
    incrementalHydrationEnabledWarned = true;
    console.warn(
      formatRuntimeError(
        RuntimeErrorCode.MISCONFIGURED_INCREMENTAL_HYDRATION,
        'Angular has detected that some `@defer` blocks use `hydrate` triggers, ' +
          'but incremental hydration was not enabled. Incremental hydration is enabled by default ' +
          'with `provideClientHydration()`. Make sure `provideClientHydration()` is included in ' +
          'your application config and that you have not opted out using `withNoIncrementalHydration()`.',
      ),
    );
  }
}
